import http.server
import socketserver
import json
import os
from datetime import datetime
from urllib.parse import parse_qs, urlparse
import threading

LOG_FILE = "application.log"
LOG_LOCK = threading.Lock()

def write_log(service_name, level, message, metadata=None):
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S.%f")[:-3]
    
    log_entry = "[%s] [%s] [%s] %s" % (timestamp, service_name, level.upper(), message)
    
    if metadata:
        metadata_str = " | " + " | ".join(["%s=%s" % (k, v) for k, v in metadata.items()])
        log_entry += metadata_str
    
    log_entry += "\n"
    
    with LOG_LOCK:
        with open(LOG_FILE, "a") as f:
            f.write(log_entry)

class LogHandler(http.server.BaseHTTPRequestHandler):
    
    def log_message(self, format, *args):
        pass
    
    def _send_response(self, status_code, message):
        self.send_response(status_code)
        self.send_header("Content-Type", "application/json")
        self.end_headers()
        response = json.dumps({"status": "success" if status_code == 200 else "error", "message": message})
        self.wfile.write(response.encode())
    
    def do_POST(self):
        if self.path.startswith("/log"):
            content_length = int(self.headers.get("Content-Length", 0))
            body = self.rfile.read(content_length).decode("utf-8")
            
            try:
                data = json.loads(body)
                
                service_name = data.get("service", "unknown")
                level = data.get("level", "info")
                message = data.get("message", "")
                metadata = data.get("metadata", {})
                
                write_log(service_name, level, message, metadata)
                
                self._send_response(200, "Log entry recorded")
            except json.JSONDecodeError:
                self._send_response(400, "Invalid JSON")
            except Exception as e:
                self._send_response(500, "Internal server error: %s" % str(e))
        else:
            self._send_response(404, "Not found")
    
    def do_GET(self):
        if self.path.startswith("/log"):
            parsed_url = urlparse(self.path)
            params = parse_qs(parsed_url.query)
            
            service_name = params.get("service", ["unknown"])[0]
            level = params.get("level", ["info"])[0]
            message = params.get("message", [""])[0]
            
            metadata = {}
            for key, value in params.items():
                if key not in ["service", "level", "message"]:
                    metadata[key] = value[0]
            
            write_log(service_name, level, message, metadata if metadata else None)
            
            self._send_response(200, "Log entry recorded")
        elif self.path == "/health":
            self._send_response(200, "OK")
        else:
            self._send_response(404, "Not found")

def run_server(port=8080):
    with socketserver.ThreadingTCPServer(("", port), LogHandler) as httpd:
        print("Logging server running on port %d" % port)
        print("Log file: %s" % os.path.abspath(LOG_FILE))
        httpd.serve_forever()

if __name__ == "__main__":
    run_server()